import requests

# Example: Using Burp Suite REST API for scanning
BURP_API_URL = 'http://localhost:1337/v0.1/'

# Start a new scan
scan_config = {
    'urls': ['https://example.com'],
    'scan_configurations': [
        {
            'type': 'Crawl',
            'name': 'Crawl strategy'
        }
    ]
}

response = requests.post(
    f'{BURP_API_URL}scan',
    json=scan_config,
    headers={'Authorization': 'Basic ' + b64encode(b'user:pass').decode()}
)

scan_id = response.json()['scan_id']
print(f'Scan started with ID: {scan_id}')

# Check scan status
status = requests.get(f'{BURP_API_URL}scan/{scan_id}')
print(f'Scan status: {status.json()["status"]}')
